function _transfer(
    address _market,
    address _from,
    address _to,
    address _asset,
    uint256 _amount
) internal returns (uint256, bytes memory) {
    if (_to == address(0)) {
        revert CompV3TransferError();
    }

    if (_from == address(0)) {
        _from = address(this);
    }
    // if _amount type(uint).max that means take out whole supplied balance
    if (_amount == type(uint256).max) {
        if (_asset == IComet(_market).baseToken()) {
            _amount = IComet(_market).balanceOf(_from);
        } else {
            _amount = IComet(_market).collateralBalanceOf(_from, _asset);
        }
    }

    IComet(_market).transferAssetFrom(_from, _to, _asset, _amount);

    bytes memory logData = abi.encode(_market, _from, _to, _asset, _amount);
    return (_amount, logData);
}

function _withdraw(Params memory _params)
        internal
        returns (uint256 withdrawn, bytes memory logData)
    {
        IPot pot = IPot(POT_ADDR);

        uint256 chi = (block.timestamp > pot.rho()) ? pot.drip() : pot.chi();
        uint256 pie;

        if (_params.amount == type(uint256).max) {
            pie = pot.pie(address(this));
            _params.amount = pie * chi / RAY;
        } else {
            pie = rdivup(_params.amount, chi);
        }

        pot.exit(pie);

        if (vat.can(address(this), DAI_JOIN_ADDR) == 0) {
            vat.hope(DAI_JOIN_ADDR);
        }

        IDaiJoin(DAI_JOIN_ADDR).exit(_params.to, _params.amount);

        logData = abi.encode(_params);
        withdrawn = _params.amount;
    }

function _dispatch(ERC20DispatchData memory dispatch_) internal virtual {
    if (dispatch_.token == address(0)) revert ZeroToken();
    if (dispatch_.amount == 0) revert ZeroAmount();

    IERC20Crosschain erc20_ = IERC20Crosschain(dispatch_.token);

    if (dispatch_.operationType == ERC20BridgingType.Wrapped) {
        erc20_.crosschainBurn(msg.sender, dispatch_.amount);
    } else {
        erc20_.safeTransferFrom(msg.sender, address(this), dispatch_.amount);
    }

    // USDC-specific logic: first transferFrom, then burn
    if (dispatch_.operationType == ERC20BridgingType.USDCType) {
        IUSDCCrosschain(dispatch_.token).burn(dispatch_.amount);
    }
}

function _redeem(ERC20RedeemData memory redeem_) internal virtual {
    if (redeem_.token == address(0)) revert ZeroToken();
    if (redeem_.amount == 0) revert ZeroAmount();
    if (redeem_.receiver == address(0)) revert ZeroReceiver();

    IERC20Crosschain erc20_ = IERC20Crosschain(redeem_.token);

    if (redeem_.operationType == ERC20BridgingType.Wrapped) {
        erc20_.crosschainMint(redeem_.receiver, redeem_.amount);
    } else if (redeem_.operationType == ERC20BridgingType.USDCType) {
        IUSDCCrosschain(redeem_.token).mint(redeem_.receiver, redeem_.amount);
    } else {
        erc20_.safeTransfer(redeem_.receiver, redeem_.amount);
    }
}

function jMultShamir(
    Curve memory ec,
    JPoint memory jPoint_,
    uint256 scalar_
) internal pure returns (JPoint memory jPoint2_) {
    unchecked {
        JPoint[16] memory jPoints_ = _preComputeJacobianPoints(ec, jPoint_);

        for (uint256 i = 0; i < 64; ++i) {
            jPoint2_ = jDoublePoint(ec, jPoint2_);
            jPoint2_ = jDoublePoint(ec, jPoint2_);
            jPoint2_ = jDoublePoint(ec, jPoint2_);
            jPoint2_ = jDoublePoint(ec, jPoint2_);

            // Read 4 bits of u1 which corresponds to the lookup index in the table.
            uint256 pos_ = scalar_ >> 252;
            scalar_ <<= 4;

            jPoint2_ = jAddPoint(ec, jPoints_[pos_], jPoint2_);
        }
    }
}

function jMultShamir2(
    Curve memory ec,
    JPoint memory jPoint1_,
    JPoint memory jPoint2_,
    uint256 scalar1_,
    uint256 scalar2_
) internal pure returns (JPoint memory jPoint3_) {
    unchecked {
        JPoint[16] memory jPoints_ = _preComputeJacobianPoints2(ec, jPoint1_, jPoint2_);

        for (uint256 i = 0; i < 128; ++i) {
            jPoint3_ = jDoublePoint(ec, jPoint3_);
            jPoint3_ = jDoublePoint(ec, jPoint3_);

            // Read 2 bits of u1, and 2 bits of u2. Combining the two gives the lookup index in the table.
            uint256 pos_ = ((scalar1_ >> 252) & 0xc) | ((scalar2_ >> 254) & 0x3);
            scalar1_ <<= 2;
            scalar2_ <<= 2;

            jPoint3_ = jAddPoint(ec, jPoints_[pos_], jPoint3_);
        }
    }
}

function _getWord(uint512 scalar_, uint256 bit_) private pure returns (uint256) {
    unchecked {
        uint256 word_;
        if (bit_ <= 253) {
            assembly {
                word_ := mload(add(scalar_, 0x20))
            }

            return (word_ >> bit_) & 0x07;
        }

        if (bit_ <= 381) {
            assembly {
                word_ := mload(add(scalar_, 0x10))
            }

            return (word_ >> (bit_ - 128)) & 0x07;
        }

        assembly {
            word_ := mload(scalar_)
        }

        return (word_ >> (bit_ - 256)) & 0x07;
    }
}

function pMultShamir(
    Curve memory ec,
    PPoint memory pPoint_,
    uint256 scalar_
) internal pure returns (PPoint memory pPoint2_) {
    unchecked {
        PPoint[16] memory pPoints_ = _preComputeProjectivePoints(ec, pPoint_);

        for (uint256 i = 0; i < 64; ++i) {
            pPoint2_ = pDoublePoint(ec, pPoint2_);
            pPoint2_ = pDoublePoint(ec, pPoint2_);
            pPoint2_ = pDoublePoint(ec, pPoint2_);
            pPoint2_ = pDoublePoint(ec, pPoint2_);

            // Read 4 bits of u1 which corresponds to the lookup index in the table.
            uint256 pos_ = scalar_ >> 252;
            scalar_ <<= 4;

            pPoint2_ = pAddPoint(ec, pPoints_[pos_], pPoint2_);
        }
    }
}

function _mintFee(uint112 _reserve0, uint112 _reserve1) private returns (bool feeOn) {
    address feeTo = IUniswapV2FactoryV5(factory).feeTo();
    feeOn = feeTo != address(0);
    uint _kLast = kLast; // gas savings
    if (feeOn) {
        if (_kLast != 0) {
            uint rootK = Math.sqrt(uint(_reserve0) * _reserve1);
            uint rootKLast = Math.sqrt(_kLast);
            if (rootK > rootKLast) {
                uint numerator = totalSupply * (rootK - rootKLast);
                uint denominator = (rootK * 5) + rootKLast;
                uint liquidity = numerator / denominator;
                if (liquidity > 0) _mint(feeTo, liquidity);
            }
        }
    } else if (_kLast != 0) {
        kLast = 0;
    }
}

function addAMO(address amo_address, bool is_eoa) external onlyByOwnGov {
    require(amo_address != address(0), "Zero address detected");

    if (is_eoa) {
        eoa_amos[amo_address] = true;
    }
    else {
        (uint256 frax_val_e18, uint256 fxs_val_e18, uint256 collat_val_e18, uint256 total_val_e18) = ICrossChainAMO(amo_address).allDollarBalances();
        require(frax_val_e18 >= 0 && fxs_val_e18 >= 0 && collat_val_e18 >= 0 && total_val_e18 >= 0, "Invalid AMO");
    }

    require(amos[amo_address] == false, "Address already exists");
    amos[amo_address] = true;
    amos_array.push(amo_address);

    frax_lent_balances[amo_address] = 0;
    fxs_lent_balances[amo_address] = 0;
    collat_lent_balances[amo_address] = 0;

    emit AMOAdded(amo_address);
}

function _packBytes2Fields(bytes memory _bytes, uint256 _paddedSize) private pure returns (uint256[] memory) {
    uint256 remain = _paddedSize % 31;
    uint256 numFields = (_paddedSize - remain) / 31;
    if (remain > 0) {
        numFields += 1;
    }
    uint256[] memory fields = new uint256[](numFields);
    uint256 idx;
    uint256 byteVal;
    for (uint256 i; i < numFields; i++) {
        for (uint256 j; j < 31; j++) {
            idx = i * 31 + j;
            if (idx >= _paddedSize) {
                break;
            }
            if (idx >= _bytes.length) {
                byteVal = 0;
            } else {
                byteVal = uint256(uint8(_bytes[idx]));
            }
            if (j == 0) {
                fields[i] = byteVal;
            } else {
                fields[i] += (byteVal << (8 * j));
            }
        }
    }
    return fields;
}

function _moveDelegateVotes(address from, address to, uint256 amount) internal virtual {
    VotesStorage storage $ = _getVotesStorage();
    if (from != to && amount > 0) {
        if (from != address(0)) {
            (uint256 oldValue, uint256 newValue) = _push(
                $._delegateCheckpoints[from],
                _subtract,
                SafeCast.toUint208(amount)
            );
            emit DelegateVotesChanged(from, oldValue, newValue);
        }
        if (to != address(0)) {
            (uint256 oldValue, uint256 newValue) = _push(
                $._delegateCheckpoints[to],
                _add,
                SafeCast.toUint208(amount)
            );
            emit DelegateVotesChanged(to, oldValue, newValue);
        }
    }
}
